server/tests/test_bmp_codec.py :: test_decode_bmp_rejects_invalid_signature
def test_decode_bmp_rejects_invalid_signature() -> None:
    try:
        decode_bmp(b"XX" + b"\x00" * 20)
    except ValueError:
        return
    raise AssertionError("Expected ValueError")

server/tests/test_bmp_codec.py :: test_decode_bmp_rejects_truncated_payload
def test_decode_bmp_rejects_truncated_payload() -> None:
    payload = bmp_bytes(solid_raster(6, 6, 1, 2, 3))[:40]
    try:
        decode_bmp(payload)
    except ValueError:
        return
    raise AssertionError("Expected ValueError")
